1074	export function makeWallMesh(
1075	  wall: WallElem,
1076	  elevM: number,
1077	  paint: ViewportPaintBundle | null,
1078	  elementsById?: Record<string, Element>,
1079	): THREE.Mesh {
1080	  if (wall.roofAttachmentId && elementsById) {
1081	    const roof = elementsById[wall.roofAttachmentId];
1082	    if (roof?.kind === 'roof') {
1083	      return makeSlopedWallMesh(
1084	        wall,
1085	        roof as Extract<Element, { kind: 'roof' }>,
1086	        elevM,
1087	        paint,
1088	        elementsById,
1089	      );
1090	    }
1091	  }
1092	  const sx = wall.start.xMm / 1000;
1093	  const sz = wall.start.yMm / 1000;
1094	  const ex = wall.end.xMm / 1000;
1095	  const ez = wall.end.yMm / 1000;
1096	  const dx = ex - sx;
