export type Vec2Mm = { xMm: number; yMm: number };

export function coerceVec2Mm(raw: unknown): Vec2Mm {
  if (Array.isArray(raw) && raw.length >= 2) {
    return { xMm: Number(raw[0] ?? 0), yMm: Number(raw[1] ?? 0) };
